-- ============================================\n-- 创建角色基础属性表\n-- ============================================\n\n-- 创建角色基础属性表\nCREATE TABLE IF NOT EXISTS `role_base_stats` (\n  `id` BIGINT NOT NULL AUTO_INCREMENT,\n  `role_id` BIGINT NOT NULL COMMENT '角色 ID',\n  `vit` INT DEFAULT 10 COMMENT '根骨',\n  `spi` INT DEFAULT 10 COMMENT '灵力',\n  `agi` INT DEFAULT 10 COMMENT '身法',\n  `wis` INT DEFAULT 10 COMMENT '悟性',\n  `lck` INT DEFAULT 10 COMMENT '气运',\n  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',\n  `updated_at` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',\n  PRIMARY KEY (`id`),\n  UNIQUE KEY `uk_role_id` (`role_id`),\n  INDEX `idx_role_id` (`role_id`)\n) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='角色基础属性表';\n